import './index.css';

import {
  Link
} from 'react-router-dom';

function TeacherDashboard() {

  const userString =
    localStorage.getItem('user');

  let user = {};

  try {

    user = userString
      ? JSON.parse(userString)
      : {};

  } catch (error) {

    console.log(error);

    user = {};

  }

  return (

    <div className="teacher-dashboard">

      {/* HEADER */}

      <div className="dashboard-header">

        <h1>
          Teacher Dashboard
        </h1>

        <button
          className="logout-btn"
          onClick={() => {

            localStorage.clear();

            window.location.href = '/';

          }}
        >

          Logout

        </button>

      </div>



      {/* WELCOME CARD */}

      <div className="welcome-card">

        <h2>
          Welcome
          {' '}
          {user.name || 'Teacher'}
        </h2>

        <p>
          Email:
          {' '}
          {user.email || 'N/A'}
        </p>

        <p>
          Role:
          {' '}
          {user.role || 'teacher'}
        </p>

      </div>



      {/* DASHBOARD CARDS */}

      <div className="dashboard-cards">

        <div className="dashboard-card">

          <h3>
            Subjects
          </h3>

          <p>
            Manage academic subjects
          </p>

          <Link to="/subjects">

            Open

          </Link>

        </div>



        <div className="dashboard-card">

          <h3>
            Add Student
          </h3>

          <p>
            Register new students
          </p>

          <Link to="/add-student">

            Open

          </Link>

        </div>



        <div className="dashboard-card">

          <h3>
            Add Marks
          </h3>

          <p>
            Insert student marks
          </p>

          <Link to="/add-marks">

            Open

          </Link>

        </div>

      </div>

    </div>

  );

}

export default TeacherDashboard;
